#include<cstdio>
#include<vector>
#include<queue>
#include<cmath>
#include<algorithm>
#include<cstring>
#include<string>
using namespace std;int W,H;bool grid[5001][5001],vis[5001][5001];double SL[5],LS;int main(){scanf("%d%d",&W,&H);char buf[20];int pi=0;while(scanf("%s",buf)!=EOF){bool c=buf[0]=='B';int l;scanf("%d",&l);for(int j=0;j<l;j++){int y=pi/W,x=pi%W;if(y<H)grid[y][x]=c;pi++;}}vector<int>bc(H);for(int y=0;y<H;y++)for(int x=0;x<W;x++)bc[y]+=grid[y][x];vector<vector<int>>groups;vector<int>g;for(int y=0;y<H;y++){if(bc[y]>W*0.8){if(g.empty()||y==g.back()+1)g.push_back(y);else{groups.push_back(g);g={y};}}else if(!g.empty()){groups.push_back(g);g.clear();}}if(!g.empty())groups.push_back(g);int bi=-1;double bd=1e9;for(int i=0;i+4<(int)groups.size();i++){double cs[5];for(int j=0;j<5;j++){double s=0;for(int v:groups[i+j])s+=v;cs[j]=s/groups[i+j].size();}double sp[4],avg=0;for(int j=0;j<4;j++){sp[j]=cs[j+1]-cs[j];avg+=sp[j];}avg/=4;double d=0;for(int j=0;j<4;j++)d+=fabs(sp[j]-avg);if(d<bd){bd=d;bi=i;}}for(int j=0;j<5;j++){double s=0;for(int v:groups[bi+j])s+=v;SL[j]=s/groups[bi+j].size();}LS=(SL[4]-SL[0])/4;vector<pair<int,string>>notes;for(int x=0;x<W;x++)for(int y=0;y<H;y++){if(grid[y][x]&&!vis[y][x]){queue<pair<int,int>>q;q.push({y,x});vector<pair<int,int>>px;int mx=W,MX=-1,my=H,MY=-1;while(!q.empty()){auto[cy,cx]=q.front();q.pop();if(cy<0||cy>=H||cx<0||cx>=W||vis[cy][cx]||!grid[cy][cx])continue;vis[cy][cx]=1;px.push_back({cy,cx});mx=min(mx,cx);MX=max(MX,cx);my=min(my,cy);MY=max(MY,cy);for(int dy=-1;dy<=1;dy++)for(int dx=-1;dx<=1;dx++)if(dy||dx)q.push({cy+dy,cx+dx});}if((int)px.size()<15)continue;map<int,pair<int,int>>yw;for(auto[py,px2]:px){if(!yw.count(py))yw[py]={px2,px2};else{yw[py].first=min(yw[py].first,px2);yw[py].second=max(yw[py].second,px2);}}int yc=-1,mw=-1;for(auto&[yy,p]:yw){int w=p.second-p.first+1;if(w>mw){mw=w;yc=yy;}}double ed=LS*0.6,eM=LS*1.5;if(mw<ed||mw>eM)continue;if(MY-my+1<ed||MX-mx+1>W*0.5)continue;int hr=LS/2,hmy=max(0,yc-hr),hMy=min(H-1,yc+hr);int bp=0;for(auto[py,px2]:px)if(py>=hmy&&py<=hMy&&px2>=mx&&px2<=MX)bp++;int tp=(MX-mx+1)*(hMy-hmy+1);double fr=tp?bp/(double)tp:1;char nt=fr>0.5?'Q':'H';const char*nm="AGFEDCBAGFEDC";double hs=LS/2;int cl=0;double md=1e9;for(int i=0;i<13;i++){double ny=SL[4]-hs*2+hs*i;double d=fabs(yc-ny);if(d<md){md=d;cl=i;}}char r[3]={nm[cl],nt,0};notes.push_back({mx,string(r)});}}sort(notes.begin(),notes.end());for(int i=0;i<(int)notes.size();i++){if(i)printf(" ");printf("%s",notes[i].second.c_str());}puts("");}